## Query Execution Design

### Query Pipeline

```python
class SearchPipeline:
    """
    Stages: Parse → Validate → Enhance → Execute → Rank → Fetch → Return
    """

    def __init__(self, opensearch_client, cache, doc_store):
        self.os = opensearch_client
        self.cache = cache          # Redis
        self.doc_store = doc_store  # DynamoDB or S3

    def search(self, request: SearchRequest) -> SearchResponse:

        # Stage 1: Parse and validate
        query = self.parse_query(request)
        if not query.is_valid():
            return SearchResponse.error(query.errors)

        # Stage 2: Cache check (for repeated queries)
        cache_key = query.cache_key()
        if cached := self.cache.get(cache_key):
            return SearchResponse.from_cache(cached)

        # Stage 3: Build OpenSearch query
        os_query = self.build_query(query)

        # Stage 4: Execute with timeout
        raw_results = self.os.search(
            index="content_current",
            body=os_query,
            timeout="3s",
            request_timeout=5
        )

        # Stage 5: Fetch full documents (IDs → full content)
        ids = [hit["_id"] for hit in raw_results["hits"]["hits"]]
        full_docs = self.doc_store.batch_get(ids)  # parallel fetch

        # Stage 6: Merge and return
        response = self.merge_results(raw_results, full_docs)

        # Stage 7: Cache results
        self.cache.setex(cache_key, ttl=300, value=response.serialize())

        return response

    def build_query(self, query: ParsedQuery) -> dict:
        """
        Build a function_score query that combines:
        - Text relevance (BM25)
        - Recency boost
        - Popularity boost
        - Business rules
        """

        must_clauses = []
        filter_clauses = []
        should_clauses = []

        # Full-text search
        if query.text:
            must_clauses.append({
                "multi_match": {
                    "query": query.text,
                    "fields": [
                        "title^3",        # Title matches worth 3x
                        "title.autocomplete^2",
                        "body_text^1",
                        "tags^2"
                    ],
                    "type": "best_fields",
                    "tie_breaker": 0.3,
                    "minimum_should_match": "75%"
                }
            })

        # Structured filters (use filter context — no scoring, cached)
        if query.category:
            filter_clauses.append({"term": {"category": query.category}})

        if query.date_range:
            filter_clauses.append({
                "range": {
                    "created_at": {
                        "gte": query.date_range.start,
                        "lte": query.date_range.end
                    }
                }
            })

        if query.tags:
            filter_clauses.append({"terms": {"tags": query.tags}})

        # Boost recent content slightly
        should_clauses.append({
            "range": {
                "created_at": {
                    "gte": "now-30d",
                    "boost": 1.5
                }
            }
        })

        base_query = {
            "bool": {
                "must": must_clauses,
                "filter": filter_clauses,
                "should": should_clauses
            }
        }

        # Wrap in function_score for popularity boost
        return {
            "query": {
                "function_score": {
                    "query": base_query,
                    "functions": [
                        {
                            "field_value_factor": {
                                "field": "popularity_score",
                                "factor": 0.1,
                                "modifier": "log1p",
                                "missing": 0
                            }
                        }
                    ],
                    "boost_mode": "sum",
                    "score_mode": "sum"
                }
            },
            "highlight": {
                "fields": {
                    "title": {},
                    "body_text": {"fragment_size": 150, "number_of_fragments": 2}
                }
            },
            "from": query.offset,
            "size": query.limit,
            "_source": ["id", "title", "category", "created_at", "s3_key"],
            "aggs": self.build_facets(query) if query.include_facets else {}
        }

    def build_facets(self, query: ParsedQuery) -> dict:
        """Faceted navigation - only compute when needed"""
        return {
            "categories": {
                "terms": {"field": "category", "size": 20}
            },
            "date_histogram": {
                "date_histogram": {
                    "field": "created_at",
                    "calendar_interval": "month"
                }
            },
            "top_tags": {
                "terms": {"field": "tags", "size": 30}
            }
        }
```

### Query Performance Patterns

```python
# PATTERN 1: Pagination — avoid deep pagination
class PaginationStrategy:

    # BAD: from/size gets expensive past page 10
    def bad_pagination(self, page: int, size: int):
        return {"from": page * size, "size": size}
        # OpenSearch must score ALL documents up to (page * size)
        # Page 1000 with size 20 = score 20,000 docs

    # GOOD: search_after for deep pagination
    def good_pagination(self, last_sort_values: list, size: int):
        return {
            "size": size,
            "sort": [
                {"_score": "desc"},
                {"created_at": "desc"},
                {"id": "asc"}  # tiebreaker must be unique
            ],
            "search_after": last_sort_values
        }

    # GOOD: Scroll API for export use cases
    def export_all(self, query: dict):
        # Use Point-in-Time API (newer, better than scroll)
        pit = self.os.open_point_in_time(index="content_current", keep_alive="5m")

        query["pit"] = {"id": pit["id"], "keep_alive": "5m"}
        query["sort"] = [{"_shard_doc": "asc"}]  # most efficient sort for scroll

        return query


